"use strict";parserFactory.register("teanovel.com",()=>new TeanovelParser),parserFactory.register("teanovel.net",()=>new TeanovelParser);class TeanovelParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=`https://www.teanovel.com/novel/${new URL(e.baseURI).pathname.split("/").pop()}/chapter-list`;return[...(await HttpClient.fetchHtml(t)).responseXML.querySelectorAll("a.flex")].map(e=>this.linkToChapter(e)).filter(e=>e.title)}linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector("p.text-sm")?.innerText?.trim()}}findContent(e){return e.querySelector("div.prose")}extractTitleImpl(e){return e.querySelector("h1")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"flex"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return e.querySelector("main img")?.src}getInformationEpubItemChildNodes(e){return[e.querySelector("article")]}}